// スレーブ側OLED (右手側) - 新レイアウト
static void slave_data(void) {
    render_logo();                              // row 0-2
    oled_set_cursor(0, 4);
    render_mod_status_gui_alt(get_mods());      // row 4-5
    render_mod_status_ctrl_shift(get_mods());   // row 6-7

    oled_set_cursor(0, 8);
    switch (get_highest_layer(layer_state)) {
        case LAYER_BASE:   oled_write("Base ", false); break;
        case LAYER_MOUSE:  oled_write("Mouse", false); break;
        case LAYER_SYMBOL: oled_write("Sym  ", false); break;
        case LAYER_RGB:    oled_write("RGB  ", false); break;
        case LAYER_NUMBER: oled_write("Num  ", false); break;
        case LAYER_NUMPAD: oled_write("Npad ", false); break;
        default:           oled_write("?????", false); break;
    }
    oled_set_cursor(0, 9);
    render_rgb_info();                          // row 9-11
    render_kkr_logo(0, 12);                     // row 12-15
}

// マスター側OLED (左手側)
static void master_data(void) {
    if (user_config.is_oled_enabled) {
        oled_clear();
        keyball_oled_default();
        keyball_oled_info();
    } else {
        render_cat();
        uint16_t m = get_current_wpm();
        oled_write_P(PSTR("WPM:"), false);
        char wpm_str[6];
        snprintf(wpm_str, sizeof(wpm_str), "%d", m);
        oled_write(wpm_str, false);
    }
}

bool oled_task_user(void) {
    if (is_keyboard_master()) {
        master_data();
    } else {
        slave_data();
    }
    return false;
}

#endif // OLED_ENABLE
